{
  "sentences": [
    {
      "text": "他長得很高，而且很瘦。",
      "pinyin": "Tā zhǎng de hěn gāo, érqiě hěn shòu.",
      "pinyin_numeric": "ta1 zhang3 de5 hen3 gao1, er2qie3 hen3 shou4",
      "translation_en": "He is tall and thin.",
      "translation_ko": "그는 키가 크고 날씬합니다."
    },
    {
      "text": "她看起來很年輕，可是已經三十歲了。",
      "pinyin": "Tā kàn qǐlái hěn niánqīng, kěshì yǐjīng sānshí suì le.",
      "pinyin_numeric": "ta1 kan4 qi3lai2 hen3 nian2qing1, ke3shi4 yi3jing1 san1shi2 sui4 le5",
      "translation_en": "She looks very young, but she is already thirty years old.",
      "translation_ko": "그녀는 아주 젊어 보이지만, 이미 서른 살입니다."
    },
    {
      "text": "那個人的頭髮很長，而且戴眼鏡。",
      "pinyin": "Nàge rén de tóufa hěn cháng, érqiě dài yǎnjìng.",
      "pinyin_numeric": "na4ge5 ren2 de5 tou2fa5 hen3 chang2, er2qie3 dai4 yan3jing4",
      "translation_en": "That person has long hair and wears glasses.",
      "translation_ko": "그 사람은 머리가 길고 안경을 쓰고 있습니다."
    },
    {
      "text": "我妹妹長得很可愛，個性也很活潑。",
      "pinyin": "Wǒ mèimei zhǎng de hěn kě'ài, gèxìng yě hěn huópō.",
      "pinyin_numeric": "wo3 mei4mei5 zhang3 de5 hen3 ke3ai4, ge4xing4 ye3 hen3 huo2po1",
      "translation_en": "My younger sister looks cute and has a lively personality.",
      "translation_ko": "제 여동생은 귀엽게 생겼고 성격도 활발합니다."
    },
    {
      "text": "他看起來很友善，可是說話不多。",
      "pinyin": "Tā kàn qǐlái hěn yǒushàn, kěshì shuōhuà bù duō.",
      "pinyin_numeric": "ta1 kan4 qi3lai2 hen3 you3shan4, ke3shi4 shuo1hua4 bu4 duo1",
      "translation_en": "He looks friendly, but he doesn't talk much.",
      "translation_ko": "그는 친근해 보이지만 말을 많이 하지 않습니다."
    },
    {
      "text": "我哥哥長得很帥，而且很幽默。",
      "pinyin": "Wǒ gēge zhǎng de hěn shuài, érqiě hěn yōumò.",
      "pinyin_numeric": "wo3 ge1ge5 zhang3 de5 hen3 shuai4, er2qie3 hen3 you1mo4",
      "translation_en": "My older brother is handsome and very humorous.",
      "translation_ko": "제 오빠는 잘생겼고 아주 유머러스합니다."
    },
    {
      "text": "那個女生看起來很溫柔，可是個性很認真。",
      "pinyin": "Nàge nǚshēng kàn qǐlái hěn wēnróu, kěshì gèxìng hěn rènzhēn.",
      "pinyin_numeric": "na4ge5 nü3sheng1 kan4 qi3lai2 hen3 wen1rou2, ke3shi4 ge4xing4 hen3 ren4zhen1",
      "translation_en": "That girl looks gentle, but she has a serious personality.",
      "translation_ko": "그 여학생은 부드러워 보이지만 성격은 아주 진지합니다."
    },
    {
      "text": "他長得不高，可是很聰明。",
      "pinyin": "Tā zhǎng de bù gāo, kěshì hěn cōngmíng.",
      "pinyin_numeric": "ta1 zhang3 de5 bu4 gao1, ke3shi4 hen3 cong1ming2",
      "translation_en": "He is not tall, but he is very smart.",
      "translation_ko": "그는 키가 크지 않지만 아주 똑똑합니다."
    },
    {
      "text": "她看起來很害羞，其實很大方。",
      "pinyin": "Tā kàn qǐlái hěn hàixiū, qíshí hěn dàfāng.",
      "pinyin_numeric": "ta1 kan4 qi3lai2 hen3 hai4xiu1, qi2shi2 hen3 da4fang1",
      "translation_en": "She looks shy, but actually she is very generous.",
      "translation_ko": "그녀는 부끄러워 보이지만 사실 아주 대범합니다."
    },
    {
      "text": "我朋友長得很胖，可是個性很有趣。",
      "pinyin": "Wǒ péngyou zhǎng de hěn pàng, kěshì gèxìng hěn yǒuqù.",
      "pinyin_numeric": "wo3 peng2you5 zhang3 de5 hen3 pang4, ke3shi4 ge4xing4 hen3 you3qu4",
      "translation_en": "My friend is fat, but he has a very interesting personality.",
      "translation_ko": "제 친구는 뚱뚱하지만 성격이 아주 재미있습니다."
    }
  ]
}
